+import { describe, it, expect, beforeEach } from 'vitest';
+import { Database } from '../../src/utils/database.js';
+import { OrderRepository } from '../../src/repositories/order.repository.js';
+import { UserRepository } from '../../src/repositories/user.repository.js';
+import { AnalyticsService } from '../../src/services/analytics.service.js';
+import type { Order, OrderItem } from '../../src/models/order.js';
+import type { User } from '../../src/models/user.js';
+import type { AnalyticsQuery, TimeSeriesQuery, MetricType } from '../../src/models/analytics.js';
+
+// ---------------------------------------------------------------------------
+// Helpers
+// ---------------------------------------------------------------------------
+
+function makeOrder(overrides: Partial<Order> & { id: string; userId: string }): Order {
+  return {
+    items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
+    total: 10,
+    status: 'pending',
+    createdAt: new Date('2025-01-15T12:00:00Z'),
+    updatedAt: new Date('2025-01-15T12:00:00Z'),
+    ...overrides,
+  };
+}
+
+function makeUser(overrides: Partial<User> & { id: string }): User {
+  return {
+    name: 'Test User',
+    email: 'test@example.com',
+    role: 'member',
+    createdAt: new Date('2025-01-15T12:00:00Z'),
+    updatedAt: new Date('2025-01-15T12:00:00Z'),
+    ...overrides,
+  };
+}
+
+// ---------------------------------------------------------------------------
+// Tests
+// ---------------------------------------------------------------------------
+
+describe('AnalyticsService', () => {
+  let db: Database;
+  let orderRepo: OrderRepository;
+  let userRepo: UserRepository;
+  let service: AnalyticsService;
+
+  beforeEach(() => {
+    db = new Database();
+    orderRepo = new OrderRepository(db);
+    userRepo = new UserRepository(db);
+    service = new AnalyticsService(orderRepo, userRepo);
+  });
+
+  // -----------------------------------------------------------------------
+  // getDashboard
+  // -----------------------------------------------------------------------
+
+  describe('getDashboard', () => {
+    it('should return dashboard data with correct structure', async () => {
+      orderRepo.save(makeOrder({ id: 'o1', userId: 'u1', total: 100, status: 'pending' }));
+      userRepo.save(makeUser({ id: 'u1' }));
+
+      const query: AnalyticsQuery = {
+        startDate: '2025-01-01T00:00:00Z',
+        endDate: '2025-01-31T23:59:59Z',
+      };
+
+      const result = await service.getDashboard(query);
+
+      expect(result.metrics).toHaveLength(4);
+      expect(result.ordersByStatus).toBeInstanceOf(Array);
+      expect(result.revenueTimeSeries).toBeInstanceOf(Array);
+      expect(result.query).toEqual(query);
+      expect(result.generatedAt).toBeDefined();
+    });
+
+    it('should compute correct metric values', async () => {
+      orderRepo.save(makeOrder({ id: 'o1', userId: 'u1', total: 50, status: 'pending' }));
+      orderRepo.save(makeOrder({ id: 'o2', userId: 'u1', total: 150, status: 'shipped' }));
+      userRepo.save(makeUser({ id: 'u1' }));
+
+      const query: AnalyticsQuery = {
+        startDate: '2025-01-01T00:00:00Z',
+        endDate: '2025-01-31T23:59:59Z',
+      };
+
+      const result = await service.getDashboard(query);
+
+      const ordersMetric = result.metrics.find((m) => m.type === 'orders');
+      expect(ordersMetric?.value).toBe(2);
+
+      const revenueMetric = result.metrics.find((m) => m.type === 'revenue');
+      expect(revenueMetric?.value).toBe(200);
+
+      const aovMetric = result.metrics.find((m) => m.type === 'average-order-value');
+      expect(aovMetric?.value).toBe(100);
+
+      const usersMetric = result.metrics.find((m) => m.type === 'users');
+      expect(usersMetric?.value).toBe(1);
+    });
+
+    it('should compute period-over-period comparison', async () => {
+      // Previous period: Dec 2024
+      orderRepo.save(makeOrder({
+        id: 'o-prev', userId: 'u1', total: 100,
+        createdAt: new Date('2024-12-15T12:00:00Z'),
+      }));
+      // Current period: Jan 2025
+      orderRepo.save(makeOrder({
+        id: 'o-cur1', userId: 'u1', total: 50,
+        createdAt: new Date('2025-01-10T12:00:00Z'),
+      }));
+      orderRepo.save(makeOrder({
+        id: 'o-cur2', userId: 'u1', total: 150,
+        createdAt: new Date('2025-01-20T12:00:00Z'),
+      }));
+
+      const query: AnalyticsQuery = {
+        startDate: '2025-01-01T00:00:00Z',
+        endDate: '2025-01-31T23:59:59Z',
+      };
+
+      const result = await service.getDashboard(query);
+
+      const ordersMetric = result.metrics.find((m) => m.type === 'orders');
+      expect(ordersMetric?.value).toBe(2);
+      expect(ordersMetric?.previousValue).toBe(1);
+      expect(ordersMetric?.changePercent).toBe(100); // 2/1 - 1 = 100%
+      expect(ordersMetric?.trend).toBe('up');
+
+      const revenueMetric = result.metrics.find((m) => m.type === 'revenue');
+      expect(revenueMetric?.value).toBe(200);
+      expect(revenueMetric?.previousValue).toBe(100);
+      expect(revenueMetric?.changePercent).toBe(100);
+    });
+
+    it('should handle empty data', async () => {
+      const query: AnalyticsQuery = {
+        startDate: '2025-01-01T00:00:00Z',
+        endDate: '2025-01-31T23:59:59Z',
+      };
+
+      const result = await service.getDashboard(query);
+
+      const ordersMetric = result.metrics.find((m) => m.type === 'orders');
+      expect(ordersMetric?.value).toBe(0);
+      expect(ordersMetric?.previousValue).toBe(0);
+      expect(ordersMetric?.changePercent).toBe(0);
+      expect(ordersMetric?.trend).toBe('flat');
+
+      const aovMetric = result.metrics.find((m) => m.type === 'average-order-value');
+      expect(aovMetric?.value).toBe(0);
+    });
+
+    it('should compute correct status breakdown', async () => {
+      orderRepo.save(makeOrder({ id: 'o1', userId: 'u1', status: 'pending' }));
+      orderRepo.save(makeOrder({ id: 'o2', userId: 'u1', status: 'pending' }));
+      orderRepo.save(makeOrder({ id: 'o3', userId: 'u1', status: 'shipped' }));
+      orderRepo.save(makeOrder({ id: 'o4', userId: 'u1', status: 'delivered' }));
+
+      const query: AnalyticsQuery = {
+        startDate: '2025-01-01T00:00:00Z',
+        endDate: '2025-01-31T23:59:59Z',
+      };
+
+      const result = await service.getDashboard(query);
+
+      const pending = result.ordersByStatus.find((s) => s.status === 'pending');
+      expect(pending?.count).toBe(2);
+      expect(pending?.percent).toBe(50);
+
+      const shipped = result.ordersByStatus.find((s) => s.status === 'shipped');
+      expect(shipped?.count).toBe(1);
+      expect(shipped?.percent).toBe(25);
+
+      const cancelled = result.ordersByStatus.find((s) => s.status === 'cancelled');
+      expect(cancelled?.count).toBe(0);
+      expect(cancelled?.percent).toBe(0);
+    });
+
+    it('should filter by userId when provided', async () => {
+      orderRepo.save(makeOrder({ id: 'o1', userId: 'u1', total: 50 }));
+      orderRepo.save(makeOrder({ id: 'o2', userId: 'u2', total: 100 }));
+
+      const query: AnalyticsQuery = {
+        startDate: '2025-01-01T00:00:00Z',
+        endDate: '2025-01-31T23:59:59Z',
+        userId: 'u1',
+      };
+
+      const result = await service.getDashboard(query);
+
+      const revenueMetric = result.metrics.find((m) => m.type === 'revenue');
+      expect(revenueMetric?.value).toBe(50);
+    });
+
+    it('should generate revenue time series with daily buckets', async () => {
+      orderRepo.save(makeOrder({
+        id: 'o1', userId: 'u1', total: 50,
+        createdAt: new Date('2025-01-02T10:00:00Z'),
+      }));
+      orderRepo.save(makeOrder({
+        id: 'o2', userId: 'u1', total: 75,
+        createdAt: new Date('2025-01-02T14:00:00Z'),
+      }));
+      orderRepo.save(makeOrder({
+        id: 'o3', userId: 'u1', total: 100,
+        createdAt: new Date('2025-01-03T10:00:00Z'),
+      }));
+
+      const query: AnalyticsQuery = {
+        startDate: '2025-01-01T00:00:00Z',
+        endDate: '2025-01-03T23:59:59Z',
+      };
+
+      const result = await service.getDashboard(query);
+
+      // Should have daily buckets from Jan 1 to Jan 3
+      expect(result.revenueTimeSeries.length).toBeGreaterThanOrEqual(3);
+
+      const jan2 = result.revenueTimeSeries.find((p) => p.label === '2025-01-02');
+      expect(jan2?.value).toBe(125); // 50 + 75
+
+      const jan3 = result.revenueTimeSeries.find((p) => p.label === '2025-01-03');
+      expect(jan3?.value).toBe(100);
+
+      const jan1 = result.revenueTimeSeries.find((p) => p.label === '2025-01-01');
+      expect(jan1?.value).toBe(0);
+    });
+  });
+
+  // -----------------------------------------------------------------------
+  // getMetric
+  // -----------------------------------------------------------------------
+
+  describe('getMetric', () => {
+    it('should return orders metric with time series', async () => {
+      orderRepo.save(makeOrder({ id: 'o1', userId: 'u1', total: 100 }));
+      orderRepo.save(makeOrder({ id: 'o2', userId: 'u1', total: 200 }));
+
+      const query: AnalyticsQuery = {
+        startDate: '2025-01-01T00:00:00Z',
+        endDate: '2025-01-31T23:59:59Z',
+      };
+
+      const result = await service.getMetric('orders', query);
+
+      expect(result.metric.type).toBe('orders');
+      expect(result.metric.value).toBe(2);
+      expect(result.metric.label).toBe('Total Orders');
+      expect(result.timeSeries).toBeInstanceOf(Array);
+      expect(result.generatedAt).toBeDefined();
+    });
+
+    it('should return revenue metric', async () => {
+      orderRepo.save(makeOrder({ id: 'o1', userId: 'u1', total: 100 }));
+      orderRepo.save(makeOrder({ id: 'o2', userId: 'u1', total: 200 }));
+
+      const query: AnalyticsQuery = {
+        startDate: '2025-01-01T00:00:00Z',
+        endDate: '2025-01-31T23:59:59Z',
+      };
+
+      const result = await service.getMetric('revenue', query);
+      expect(result.metric.value).toBe(300);
+      expect(result.metric.label).toBe('Total Revenue');
+    });
+
+    it('should return users metric', async () => {
+      userRepo.save(makeUser({ id: 'u1', email: 'a@test.com', createdAt: new Date('2025-01-10T00:00:00Z') }));
+      userRepo.save(makeUser({ id: 'u2', email: 'b@test.com', createdAt: new Date('2025-01-20T00:00:00Z') }));
+
+      const query: AnalyticsQuery = {
+        startDate: '2025-01-01T00:00:00Z',
+        endDate: '2025-01-31T23:59:59Z',
+      };
+
+      const result = await service.getMetric('users', query);
+      expect(result.metric.value).toBe(2);
+      expect(result.metric.label).toBe('New Users');
+    });
+
+    it('should return average-order-value metric', async () => {
+      orderRepo.save(makeOrder({ id: 'o1', userId: 'u1', total: 100 }));
+      orderRepo.save(makeOrder({ id: 'o2', userId: 'u1', total: 200 }));
+
+      const query: AnalyticsQuery = {
+        startDate: '2025-01-01T00:00:00Z',
+        endDate: '2025-01-31T23:59:59Z',
+      };
+
+      const result = await service.getMetric('average-order-value', query);
+      expect(result.metric.value).toBe(150);
+      expect(result.metric.label).toBe('Avg Order Value');
+    });
+
+    it('should handle zero orders for average-order-value', async () => {
+      const query: AnalyticsQuery = {
+        startDate: '2025-01-01T00:00:00Z',
+        endDate: '2025-01-31T23:59:59Z',
+      };
+
+      const result = await service.getMetric('average-order-value', query);
+      expect(result.metric.value).toBe(0);
+    });
+
+    it('should compute trend correctly for declining metric', async () => {
+      // Previous period: Dec 2024 — 3 orders
+      orderRepo.save(makeOrder({ id: 'o-prev1', userId: 'u1', createdAt: new Date('2024-12-10T00:00:00Z') }));
+      orderRepo.save(makeOrder({ id: 'o-prev2', userId: 'u1', createdAt: new Date('2024-12-15T00:00:00Z') }));
+      orderRepo.save(makeOrder({ id: 'o-prev3', userId: 'u1', createdAt: new Date('2024-12-20T00:00:00Z') }));
+      // Current period: Jan 2025 — 1 order
+      orderRepo.save(makeOrder({ id: 'o-cur1', userId: 'u1', createdAt: new Date('2025-01-15T00:00:00Z') }));
+
+      const query: AnalyticsQuery = {
+        startDate: '2025-01-01T00:00:00Z',
+        endDate: '2025-01-31T23:59:59Z',
+      };
+
+      const result = await service.getMetric('orders', query);
+      expect(result.metric.trend).toBe('down');
+      expect(result.metric.changePercent).toBeCloseTo(-66.67, 1);
+    });
+
+    it('should return flat trend when previous is zero', async () => {
+      orderRepo.save(makeOrder({ id: 'o1', userId: 'u1', createdAt: new Date('2025-01-15T00:00:00Z') }));
+
+      const query: AnalyticsQuery = {
+        startDate: '2025-01-01T00:00:00Z',
+        endDate: '2025-01-31T23:59:59Z',
+      };
+
+      const result = await service.getMetric('orders', query);
+      // previousValue is 0, so changePercent stays 0 => flat
+      expect(result.metric.trend).toBe('flat');
+      expect(result.metric.changePercent).toBe(0);
+    });
+  });
+
+  // -----------------------------------------------------------------------
+  // getTimeSeries
+  // -----------------------------------------------------------------------
+
+  describe('getTimeSeries', () => {
+    it('should bucket orders by day', async () => {
+      orderRepo.save(makeOrder({
+        id: 'o1', userId: 'u1',
+        createdAt: new Date('2025-01-01T08:00:00Z'),
+      }));
+      orderRepo.save(makeOrder({
+        id: 'o2', userId: 'u1',
+        createdAt: new Date('2025-01-01T16:00:00Z'),
+      }));
+      orderRepo.save(makeOrder({
+        id: 'o3', userId: 'u1',
+        createdAt: new Date('2025-01-02T10:00:00Z'),
+      }));
+
+      const query: TimeSeriesQuery = {
+        startDate: '2025-01-01T00:00:00Z',
+        endDate: '2025-01-02T23:59:59Z',
+        metric: 'orders',
+        granularity: 'day',
+      };
+
+      const result = await service.getTimeSeries(query);
+
+      expect(result.metric).toBe('orders');
+      expect(result.granularity).toBe('day');
+
+      const jan1 = result.points.find((p) => p.label === '2025-01-01');
+      expect(jan1?.value).toBe(2);
+
+      const jan2 = result.points.find((p) => p.label === '2025-01-02');
+      expect(jan2?.value).toBe(1);
+    });
+
+    it('should bucket orders by hour', async () => {
+      orderRepo.save(makeOrder({
+        id: 'o1', userId: 'u1',
+        createdAt: new Date('2025-01-01T10:30:00Z'),
+      }));
+      orderRepo.save(makeOrder({
+        id: 'o2', userId: 'u1',
+        createdAt: new Date('2025-01-01T10:45:00Z'),
+      }));
+      orderRepo.save(makeOrder({
+        id: 'o3', userId: 'u1',
+        createdAt: new Date('2025-01-01T11:15:00Z'),
+      }));
+
+      const query: TimeSeriesQuery = {
+        startDate: '2025-01-01T10:00:00Z',
+        endDate: '2025-01-01T12:00:00Z',
+        metric: 'orders',
+        granularity: 'hour',
+      };
+
+      const result = await service.getTimeSeries(query);
+
+      const hour10 = result.points.find((p) => p.label === '10:00');
+      expect(hour10?.value).toBe(2);
+
+      const hour11 = result.points.find((p) => p.label === '11:00');
+      expect(hour11?.value).toBe(1);
+    });
+
+    it('should bucket revenue by week', async () => {
+      // Week of Jan 6 (Mon)
+      orderRepo.save(makeOrder({
+        id: 'o1', userId: 'u1', total: 50,
+        createdAt: new Date('2025-01-07T10:00:00Z'),
+      }));
+      // Week of Jan 13
+      orderRepo.save(makeOrder({
+        id: 'o2', userId: 'u1', total: 100,
+        createdAt: new Date('2025-01-14T10:00:00Z'),
+      }));
+
+      const query: TimeSeriesQuery = {
+        startDate: '2025-01-06T00:00:00Z',
+        endDate: '2025-01-19T23:59:59Z',
+        metric: 'revenue',
+        granularity: 'week',
+      };
+
+      const result = await service.getTimeSeries(query);
+      expect(result.points.length).toBeGreaterThanOrEqual(2);
+
+      // First week bucket should contain 50
+      expect(result.points[0]?.value).toBe(50);
+      // Second week bucket should contain 100
+      expect(result.points[1]?.value).toBe(100);
+    });
+
+    it('should bucket by month', async () => {
+      orderRepo.save(makeOrder({
+        id: 'o1', userId: 'u1', total: 100,
+        createdAt: new Date('2025-01-15T10:00:00Z'),
+      }));
+      orderRepo.save(makeOrder({
+        id: 'o2', userId: 'u1', total: 200,
+        createdAt: new Date('2025-02-15T10:00:00Z'),
+      }));
+
+      const query: TimeSeriesQuery = {
+        startDate: '2025-01-01T00:00:00Z',
+        endDate: '2025-02-28T23:59:59Z',
+        metric: 'revenue',
+        granularity: 'month',
+      };
+
+      const result = await service.getTimeSeries(query);
+
+      const jan = result.points.find((p) => p.label === '2025-01');
+      expect(jan?.value).toBe(100);
+
+      const feb = result.points.find((p) => p.label === '2025-02');
+      expect(feb?.value).toBe(200);
+    });
+
+    it('should bucket users', async () => {
+      userRepo.save(makeUser({ id: 'u1', email: 'a@test.com', createdAt: new Date('2025-01-05T00:00:00Z') }));
+      userRepo.save(makeUser({ id: 'u2', email: 'b@test.com', createdAt: new Date('2025-01-05T12:00:00Z') }));
+      userRepo.save(makeUser({ id: 'u3', email: 'c@test.com', createdAt: new Date('2025-01-10T00:00:00Z') }));
+
+      const query: TimeSeriesQuery = {
+        startDate: '2025-01-01T00:00:00Z',
+        endDate: '2025-01-15T23:59:59Z',
+        metric: 'users',
+        granularity: 'day',
+      };
+
+      const result = await service.getTimeSeries(query);
+
+      const jan5 = result.points.find((p) => p.label === '2025-01-05');
+      expect(jan5?.value).toBe(2);
+
+      const jan10 = result.points.find((p) => p.label === '2025-01-10');
+      expect(jan10?.value).toBe(1);
+    });
+
+    it('should default granularity to day', async () => {
+      const query: TimeSeriesQuery = {
+        startDate: '2025-01-01T00:00:00Z',
+        endDate: '2025-01-03T23:59:59Z',
+        metric: 'orders',
+      };
+
+      const result = await service.getTimeSeries(query);
+      expect(result.granularity).toBe('day');
+    });
+
+    it('should return empty buckets when no data', async () => {
+      const query: TimeSeriesQuery = {
+        startDate: '2025-01-01T00:00:00Z',
+        endDate: '2025-01-03T23:59:59Z',
+        metric: 'orders',
+        granularity: 'day',
+      };
+
+      const result = await service.getTimeSeries(query);
+      expect(result.points.length).toBeGreaterThanOrEqual(3);
+      for (const point of result.points) {
+        expect(point.value).toBe(0);
+      }
+    });
+
+    it('should compute average-order-value per bucket', async () => {
+      orderRepo.save(makeOrder({
+        id: 'o1', userId: 'u1', total: 100,
+        createdAt: new Date('2025-01-01T08:00:00Z'),
+      }));
+      orderRepo.save(makeOrder({
+        id: 'o2', userId: 'u1', total: 200,
+        createdAt: new Date('2025-01-01T16:00:00Z'),
+      }));
+
+      const query: TimeSeriesQuery = {
+        startDate: '2025-01-01T00:00:00Z',
+        endDate: '2025-01-01T23:59:59Z',
+        metric: 'average-order-value',
+        granularity: 'day',
+      };
+
+      const result = await service.getTimeSeries(query);
+      const jan1 = result.points.find((p) => p.label === '2025-01-01');
+      expect(jan1?.value).toBe(150); // (100 + 200) / 2
+    });
+
+    it('should handle single data point', async () => {
+      orderRepo.save(makeOrder({
+        id: 'o1', userId: 'u1', total: 42,
+        createdAt: new Date('2025-01-01T12:00:00Z'),
+      }));
+
+      const query: TimeSeriesQuery = {
+        startDate: '2025-01-01T00:00:00Z',
+        endDate: '2025-01-01T23:59:59Z',
+        metric: 'revenue',
+        granularity: 'day',
+      };
+
+      const result = await service.getTimeSeries(query);
+      expect(result.points.length).toBeGreaterThanOrEqual(1);
+
+      const jan1 = result.points.find((p) => p.label === '2025-01-01');
+      expect(jan1?.value).toBe(42);
+    });
+  });
+
+  // -----------------------------------------------------------------------
+  // getTopProducts
+  // -----------------------------------------------------------------------
+
+  describe('getTopProducts', () => {
+    it('should rank products by revenue', async () => {
+      orderRepo.save(makeOrder({
+        id: 'o1', userId: 'u1', total: 100,
+        items: [
+          { productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 25 },
+          { productId: 'p2', name: 'Gadget', quantity: 1, unitPrice: 50 },
+        ],
+      }));
+      orderRepo.save(makeOrder({
+        id: 'o2', userId: 'u1', total: 150,
+        items: [
+          { productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 25 },
+          { productId: 'p3', name: 'Doohickey', quantity: 5, unitPrice: 25 },
+        ],
+      }));
+
+      const query: AnalyticsQuery = {
+        startDate: '2025-01-01T00:00:00Z',
+        endDate: '2025-01-31T23:59:59Z',
+      };
+
+      const result = await service.getTopProducts(query);
+
