  describe('getTopProducts', () => {
    it('should rank products by revenue', async () => {
      orderRepo.save(makeOrder({
        id: 'o1', userId: 'u1', total: 100,
        items: [
          { productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 25 },
          { productId: 'p2', name: 'Gadget', quantity: 1, unitPrice: 50 },
        ],
      }));
      orderRepo.save(makeOrder({
        id: 'o2', userId: 'u1', total: 150,
        items: [
          { productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 25 },
          { productId: 'p3', name: 'Doohickey', quantity: 5, unitPrice: 25 },
        ],
      }));

      const query: AnalyticsQuery = {
        startDate: '2025-01-01T00:00:00Z',
        endDate: '2025-01-31T23:59:59Z',
      };

      const result = await service.getTopProducts(query);

      expect(result.products).toHaveLength(3);
      // p3: 5*25 = 125, p1: 2*25 + 1*25 = 75, p2: 1*50 = 50
      expect(result.products[0]?.productId).toBe('p3');
      expect(result.products[0]?.totalRevenue).toBe(125);
      expect(result.products[0]?.totalQuantity).toBe(5);

      expect(result.products[1]?.productId).toBe('p1');
      expect(result.products[1]?.totalRevenue).toBe(75);
      expect(result.products[1]?.totalQuantity).toBe(3);

      expect(result.products[2]?.productId).toBe('p2');
      expect(result.products[2]?.totalRevenue).toBe(50);
    });

    it('should respect limit parameter', async () => {
      orderRepo.save(makeOrder({
        id: 'o1', userId: 'u1', total: 100,
