  describe('edge cases', () => {
    it('should handle large dataset without error', async () => {
      for (let i = 0; i < 100; i++) {
        orderRepo.save(makeOrder({
          id: `o${i}`, userId: 'u1', total: i * 10,
          createdAt: new Date(`2025-01-${String((i % 28) + 1).padStart(2, '0')}T12:00:00Z`),
          items: [{ productId: `p${i % 5}`, name: `Product ${i % 5}`, quantity: 1, unitPrice: i * 10 }],
        }));
      }

      const query: AnalyticsQuery = {
        startDate: '2025-01-01T00:00:00Z',
        endDate: '2025-01-31T23:59:59Z',
      };

      const dashboard = await service.getDashboard(query);
      expect(dashboard.metrics.find((m) => m.type === 'orders')?.value).toBe(100);
      expect(dashboard.ordersByStatus.reduce((sum, s) => sum + s.count, 0)).toBe(100);

      const topProducts = await service.getTopProducts(query, 5);
      expect(topProducts.products).toHaveLength(5);
    });

    it('should handle orders at range boundaries (inclusive)', async () => {
      orderRepo.save(makeOrder({
        id: 'o-start', userId: 'u1', total: 10,
        createdAt: new Date('2025-01-01T00:00:00Z'),
      }));
      orderRepo.save(makeOrder({
        id: 'o-end', userId: 'u1', total: 20,
        createdAt: new Date('2025-01-31T23:59:59Z'),
      }));

      const query: AnalyticsQuery = {
        startDate: '2025-01-01T00:00:00Z',
        endDate: '2025-01-31T23:59:59Z',
      };

      const result = await service.getDashboard(query);
      expect(result.metrics.find((m) => m.type === 'orders')?.value).toBe(2);
      expect(result.metrics.find((m) => m.type === 'revenue')?.value).toBe(30);
    });

    it('should handle orders outside date range', async () => {
      orderRepo.save(makeOrder({
        id: 'o1', userId: 'u1', total: 100,
        createdAt: new Date('2024-12-31T23:59:59Z'),
      }));
      orderRepo.save(makeOrder({
        id: 'o2', userId: 'u1', total: 200,
        createdAt: new Date('2025-02-01T00:00:01Z'),
      }));

      const query: AnalyticsQuery = {
        startDate: '2025-01-01T00:00:00Z',
        endDate: '2025-01-31T23:59:59Z',
      };

      const result = await service.getDashboard(query);
      expect(result.metrics.find((m) => m.type === 'orders')?.value).toBe(0);
    });

    it('should not leak bucket state between successive calls', async () => {
      orderRepo.save(makeOrder({
        id: 'o1', userId: 'u1', total: 100,
        createdAt: new Date('2025-01-15T12:00:00Z'),
      }));

      const query: AnalyticsQuery = {
        startDate: '2025-01-01T00:00:00Z',
        endDate: '2025-01-31T23:59:59Z',
      };

      // Call getDashboard twice — bucket state should not leak
      const result1 = await service.getDashboard(query);
      const result2 = await service.getDashboard(query);

      const rev1 = result1.metrics.find((m) => m.type === 'revenue')?.value;
      const rev2 = result2.metrics.find((m) => m.type === 'revenue')?.value;
      expect(rev1).toBe(rev2);
    });
